 5	/**
 6	 * In-memory catalog of sub-agent definitions, with priority-based resolution.
 7	 *
 8	 * <p>Definitions are registered in priority order: project-level definitions
 9	 * overwrite user-level, which overwrite built-in. {@link #resolve} returns
10	 * the highest-priority version for a given name.</p>
11	 */
12	public class AgentCatalog {
13	
14	    private final Map<String, SubAgentSpec> agents = new LinkedHashMap<>();
15	
16	    public AgentCatalog() {}
17	
18	    /**
19	     * Register a definition, overwriting any existing entry with the same name.
20	     */
21	    public void register(SubAgentSpec spec) {
22	        agents.put(spec.name(), spec);
23	    }
24	
25	    /**
26	     * Bulk-register definitions from a map.
27	     */
28	    public void registerAll(Map<String, SubAgentSpec> specs) {
29	        agents.putAll(specs);
30	    }
31	
32	    /**
33	     * Resolve a sub-agent type name to its highest-priority spec.
34	     *
35	     * @param name the subagent_type to look up
36	     * @return the spec, or null if not found
37	     */
38	    public SubAgentSpec resolve(String name) {
39	        return agents.get(name);
40	    }
41	
42	    /**
43	     * @return sorted list of all registered agent names (excluding internal _fork)
44	     */
45	    public List<String> listNames() {
46	        var names = new ArrayList<String>();
47	        for (String name : agents.keySet()) {
48	            if (!name.startsWith("_")) {
49	                names.add(name);
50	            }
51	        }
52	        Collections.sort(names);
53	        return names;
54	    }
55	
56	    /**
57	     * @return the number of registered definitions
58	     */
59	    public int size() {
60	        return agents.size();
61	    }
62	
63	    /**
64	     * @return unmodifiable view of all registered specs
65	     */
66	    public Map<String, SubAgentSpec> all() {
67	        return Collections.unmodifiableMap(agents);
68	    }
69	}

