  3	import com.mewcode.conversation.ConversationManager;
  4	import com.mewcode.conversation.Message;
  5	import com.mewcode.conversation.ToolResultBlock;
  6	import com.mewcode.conversation.ToolUseBlock;
  7	
  8	import java.util.ArrayList;
  9	import java.util.HashSet;
 10	import java.util.List;
 11	import java.util.Set;
 12	
 13	/**
 14	 * Builds a forked conversation from the parent's message history.
 15	 *
 16	 * <p>Three steps:</p>
 17	 * <ol>
 18	 *   <li>Deep-copy all parent messages</li>
 19	 *   <li>Patch unterminated tool_use blocks with placeholder tool_results</li>
 20	 *   <li>Append the Fork Boilerplate + task as a user message</li>
 21	 * </ol>
 22	 */
 23	public final class ForkBuilder {
 24	
 25	    /** Tag used to detect nested fork attempts in conversation history. */
 26	    public static final String FORK_BOILERPLATE_TAG = "<fork_boilerplate>";
 27	
 28	    /** Full Fork Boilerplate injected as the first user message. */
 29	    public static final String FORK_BOILERPLATE = FORK_BOILERPLATE_TAG + """
 30	
 31	            You are a forked worker process. You are NOT the main agent.
 32	            Rules (non-negotiable):
 33	            1. Do NOT fork again.
 34	            2. Do NOT converse, ask questions, or request confirmation.
 35	            3. Use tools directly: read files, search code, make changes.
 36	            4. Stay strictly within your assigned task scope.
 37	            5. When done, produce a complete final response. Do not self-limit length.
 38	            </fork_boilerplate>""";
 39	
 40	    private ForkBuilder() {}
 41	
 42	    /**
 43	     * Build a forked ConversationManager from the parent's message history.
 44	     *
 45	     * @param parent the parent agent's conversation
 46	     * @return a new ConversationManager with copied messages + task
 47	     */
 48	    public static ConversationManager buildForkedConversation(ConversationManager parent) {
 49	        ConversationManager forked = new ConversationManager();
 50	
 51	        List<Message> source = parent.getMessages();
 52	        List<Message> copied = deepCopyMessages(source);
 53	
 54	        // Collect tool_use_ids that have corresponding tool_results
 55	        Set<String> resolvedIds = new HashSet<>();
 56	        for (Message msg : copied) {
 57	            if (msg.getToolResults() != null) {
 58	                for (ToolResultBlock trb : msg.getToolResults()) {
 59	                    resolvedIds.add(trb.toolUseId());
 60	                }
 61	            }
 62	        }
 63	
 64	        // Replay messages, patching unterminated tool_use blocks
 65	        for (Message msg : copied) {
 66	            if (msg.getToolUses() != null && !msg.getToolUses().isEmpty()) {
 67	                // Check which tool_use_ids are unresolved
 68	                List<ToolUseBlock> unresolved = new ArrayList<>();
 69	                for (ToolUseBlock tu : msg.getToolUses()) {
 70	                    if (!resolvedIds.contains(tu.toolUseId())) {
 71	                        unresolved.add(tu);
 72	                    }
 73	                }
 74	
 75	                forked.getMessagesMutable().add(msg);
 76	
 77	                // Patch: add placeholder tool_results for unresolved tool_use blocks
 78	                if (!unresolved.isEmpty()) {
 79	                    List<ToolResultBlock> placeholders = new ArrayList<>();
 80	                    for (ToolUseBlock tu : unresolved) {
 81	                        placeholders.add(new ToolResultBlock(
 82	                                tu.toolUseId(),
 83	                                "(tool execution interrupted by fork)",
 84	                                false));
 85	                    }
 86	                    Message placeholderMsg = new Message("user", "");
 87	                    placeholderMsg.setToolResults(placeholders);
 88	                    forked.getMessagesMutable().add(placeholderMsg);
 89	                }
 90	            } else if (msg.getToolResults() != null && !msg.getToolResults().isEmpty()) {
 91	                forked.getMessagesMutable().add(msg);
 92	            } else if ("assistant".equals(msg.getRole())) {
 93	                forked.getMessagesMutable().add(msg);
 94	            } else if ("user".equals(msg.getRole()) || "system".equals(msg.getRole())) {
 95	                forked.getMessagesMutable().add(msg);
 96	            }
 97	        }
 98	
 99	        return forked;
100	    }
