102	    /**
103	     * Build the initial user message for the forked agent.
104	     */
105	    public static String buildTaskMessage(String task) {
106	        return FORK_BOILERPLATE + "\n\nYour task:\n" + task;
107	    }
108	
109	    /**
110	     * Check if a conversation contains the Fork Boilerplate tag,
111	     * indicating it's already a forked context (nested fork detection).
112	     */
113	    public static boolean containsForkBoilerplate(ConversationManager conv) {
114	        for (Message msg : conv.getMessages()) {
115	            if (msg.getContent() != null && msg.getContent().contains(FORK_BOILERPLATE_TAG)) {
116	                return true;
117	            }
118	        }
119	        return false;
120	    }
121	
122	    /**
123	     * Check if a list of messages contains the Fork Boilerplate tag.
124	     */
125	    public static boolean containsForkBoilerplate(List<Message> messages) {
126	        for (Message msg : messages) {
127	            if (msg.getContent() != null && msg.getContent().contains(FORK_BOILERPLATE_TAG)) {
128	                return true;
129	            }
130	        }
131	        return false;
132	    }
