136	    /**
137	     * Deep-copy a list of messages so the forked conversation is independent.
138	     */
139	    private static List<Message> deepCopyMessages(List<Message> source) {
140	        List<Message> result = new ArrayList<>();
141	        for (Message msg : source) {
142	            Message copy = new Message(msg.getRole(), msg.getContent());
143	
144	            // Copy thinking blocks
145	            if (msg.getThinkingBlocks() != null) {
146	                copy.setThinkingBlocks(new ArrayList<>(msg.getThinkingBlocks()));
147	            }
148	
149	            // Copy tool uses
150	            if (msg.getToolUses() != null) {
151	                List<ToolUseBlock> toolUsesCopy = new ArrayList<>();
152	                for (ToolUseBlock tu : msg.getToolUses()) {
153	                    toolUsesCopy.add(new ToolUseBlock(
154	                            tu.toolUseId(),
155	                            tu.toolName(),
156	                            tu.arguments() != null ? new java.util.LinkedHashMap<>(tu.arguments()) : null));
157	                }
158	                copy.setToolUses(toolUsesCopy);
159	            }
160	
161	            // Copy tool results
162	            if (msg.getToolResults() != null) {
163	                List<ToolResultBlock> toolResultsCopy = new ArrayList<>();
164	                for (ToolResultBlock trb : msg.getToolResults()) {
165	                    toolResultsCopy.add(new ToolResultBlock(
166	                            trb.toolUseId(), trb.content(), trb.isError()));
167	                }
168	                copy.setToolResults(toolResultsCopy);
169	            }
170	
171	            result.add(copy);
172	        }
173	        return result;
174	    }
175	}

