294	    @Override
295	    public String runSubAgent(String body, List<Message> seed, List<String> allowedTools, String model) {
296	        // If a different model is requested, warn but use current provider
297	        if (model != null && !model.isBlank()) {
298	            offerEvent(AgentEvent.of(AgentEventType.PROGRESS)
299	                    .message("[system warning] Skill requested model '" + model
300	                            + "', but fork sub-agents always use the current provider's model. "
301	                            + "Multi-provider model switching is not yet implemented.")
302	                    .build());
303	        }
304	
305	        // Create a fresh ConversationManager for the sub-agent
306	        var subConversationManager = new ConversationManager();
307	        // Inject seed messages as history
308	        for (var msg : seed) {
309	            subConversationManager.getMessagesMutable().add(msg);
310	        }
311	
312	        // Inject the skill SOP as a system-reminder
313	        if (body != null && !body.isBlank()) {
314	            subConversationManager.getMessagesMutable().add(new Message("user",
315	                    "<system-reminder>\n## Active Skill\n\n" + body + "\n</system-reminder>"));
316	        }
317	
318	        // Build a temporary SubAgentSpec for this skill fork
319	        // Use SubAgent infrastructure for tool filtering
320	        List<String> disallowedTools = List.of();
321	        if (allowedTools != null && !allowedTools.isEmpty()) {
322	            // allowedTools is a whitelist — compute disallowed from full registry
323	            List<String> allToolNames = toolRegistry.getAllTools().stream()
324	                    .map(Tool::getName)
325	                    .toList();
326	            List<String> computedDisallowed = new java.util.ArrayList<>();
327	            for (String tooltName : allToolNames) {
328	                if (!allowedTools.contains(tooltName) && !"Skill".equals(tooltName)) {
329	                    computedDisallowed.add(tooltName);
330	                }
331	            }
332	            disallowedTools = computedDisallowed;
333	        }
334	
335	        var skillForkSpec = new SubAgentSpec(
336	                "skill-fork",
337	                "Skill fork sub-agent",
338	                List.of(),      // no whitelist — handled by disallowed
339	                disallowedTools,
340	                body,           // system prompt = skill SOP
341	                maxIterations,  // inherit parent's max turns
342	                null,           // inherit model
343	                null,           // default permission mode
344	                false
345	        );
346	
347	        // Build tool filter via SubAgent's ToolFilter
348	        var toolFilter = ToolFilter.buildFilter(skillForkSpec, false, false);
349	
350	        // Create sub-agent
351	        var subEventQueue = new LinkedBlockingQueue<AgentEvent>(256);
352	        var subLoop = new AgentLoop(
353	                provider,
354	                toolRegistry,
355	                subConversationManager,
356	                subEventQueue,
357	                maxIterations,
358	                (int) (streamTimeoutMs / 1000),
359	                permissionChecker
360	        );
361	        subLoop.setPlanMode(false);
362	        subLoop.setWorkingDirectory(workingDirectory);
363	        subLoop.setSessionId(sessionId);
364	        subLoop.setContextWindow(contextWindow);
365	        subLoop.setReplacementState(this.replacementState.copy());
366	        subLoop.setToolFilter(toolFilter);
367	        subLoop.configureAsSubAgent("skill-fork", body, maxIterations, "default");
368	
369	        // Run the sub-agent synchronously on a new thread
370	        Thread subThread = new Thread(subLoop, "skill-fork-agent");
371	        subThread.start();
372	
373	        // Collect the final text output
374	        var output = new StringBuilder();
375	        boolean hadError = false;
376	        String errorMsg = "";
377	
378	        try {
379	            while (true) {
380	                var event = subEventQueue.poll(streamTimeoutMs, TimeUnit.MILLISECONDS);
381	                if (event == null) {
382	                    hadError = true;
383	                    errorMsg = "Fork sub-agent timed out after " + (streamTimeoutMs / 1000) + "s";
384	                    break;
385	                }
386	
387	                switch (event.getType()) {
388	                    case TEXT_DELTA -> {
389	                        if (event.getText() != null) {
390	                            // 只收集实际输出文本，排除思考过程
391	                            var ct = event.getChunkType();
392	                            if (ct == null || ct == com.mewcode.provider.ChunkType.TEXT) {
393	                                output.append(event.getText());
394	                            }
395	                        }
396	                    }
397	                    case ERROR -> {
398	                        hadError = true;
399	                        errorMsg = event.getMessage() != null ? event.getMessage() : "Unknown error";
400	                    }
401	                    case LOOP_FINISHED -> {
402	                        return output.toString().trim();
403	                    }
404	                    case CANCELLED -> {
405	                        hadError = true;
406	                        errorMsg = "Fork sub-agent was cancelled";
407	                    }
408	                    default -> {}
409	                }
410	
411	                if (hadError) {
412	                    break;
413	                }
414	            }
415	        } catch (InterruptedException e) {
416	            Thread.currentThread().interrupt();
417	            errorMsg = "Fork sub-agent was interrupted";
418	        }
419	
420	        subLoop.cancel();
421	        return "[fork error] " + errorMsg;
422	
423	    }
