852	    /**
853	     * Block the agent thread until the user responds via the UI.
854	     */
855	    private PermissionResponse waitForPermission(ToolCall tc, PermissionResult checkResult) {
856	        waitingForPermission = true;
857	        try {
858	            String message = checkResult.getReason();
859	            // Annotate with sub-agent identity if applicable
860	            if (isSubAgent && subAgentName != null) {
861	                message = "[SubAgent " + subAgentName + "] " + message;
862	            }
863	            offerEvent(AgentEvent.of(AgentEventType.PERMISSION_REQUIRED)
864	                    .permissionToolCall(tc)
865	                    .toolName(tc.getName())
866	                    .callId(tc.getId())
867	                    .message(message)
868	                    .build());
869	
870	            // For sub-agents, use a 60-second timeout (vs indefinite for main agent)
871	            if (isSubAgent) {
872	                PermissionResponse permissionResponse = permissionResponseQueue.poll(60, TimeUnit.SECONDS);
873	                // timeout → auto-deny
874	                return Objects.requireNonNullElse(permissionResponse, PermissionResponse.DENY);
875	            }
876	
877	            // Block until UI calls respondToPermission()
878	            return permissionResponseQueue.take();
879	        } catch (InterruptedException e) {
880	            Thread.currentThread().interrupt();
881	            return PermissionResponse.DENY;
882	        } finally {
883	            waitingForPermission = false;
884	        }
885	    }
