896	
897	    /**
898	     * Adjust a permission result based on the sub-agent's permission mode.
899	     */
900	    private PermissionResult adjustForSubAgentMode(PermissionResult permissionResult, Tool tool) {
901	        if (subAgentPermissionMode == null) return permissionResult;
902	
903	        return switch (subAgentPermissionMode) {
904	            case "bypassPermissions" -> permissionResult.isDeny()
905	                    ? permissionResult  // hard denies (sandbox, dangerous commands) still pass through
906	                    : PermissionResult.allow("dontAsk mode: auto-allow " + tool.getName());
907	
908	            case "dontAsk" -> permissionResult.isAsk()
909	                    ? PermissionResult.allow("dontAsk mode: auto-allow " + tool.getName())
910	                    : permissionResult;
911	
912	            case "acceptEdits" -> (permissionResult.isAsk() && tool.category() == com.mewcode.tool.ToolCategory.WRITE)
913	                    ? PermissionResult.allow("acceptEdits mode: auto-allow write " + tool.getName())
914	                    : permissionResult;
915	
916	            case "plan" -> tool.category() == com.mewcode.tool.ToolCategory.READ
917	                    ? PermissionResult.allow("plan mode: read-only tool " + tool.getName())
918	                    : PermissionResult.deny("plan mode: only read-only tools allowed",
919	                            "切换到执行模式或绕过权限");
920	
921	            default -> permissionResult;  // "default" — no change
922	        };
923	    }
