 14	/**
 15	 * Loads sub-agent definitions from three sources (in priority order):
 16	 * <ol>
 17	 *   <li>Built-in specs from classpath {@code subagent/builtin/*.md}</li>
 18	 *   <li>User-level definitions from {@code ~/.mewcode/agents/*.md}</li>
 19	 *   <li>Project-level definitions from {@code <projectRoot>/.mewcode/agents/*.md}</li>
 20	 * </ol>
 21	 * Later sources override earlier ones with the same agent name.
 22	 *
 23	 * <p>Each {@code .md} file uses optional YAML frontmatter delimited by {@code ---}
 24	 * followed by a Markdown body that becomes the system prompt override.</p>
 25	 */
 26	public final class AgentLoader {
 27	
 28	    private static final ObjectMapper YAML = new ObjectMapper(new YAMLFactory());
 29	
 30	    private AgentLoader() {}
 31	
 32	    /**
 33	     * Loads all agent definitions: built-in, user-level, then project-level.
 34	     *
 35	     * @param projectRoot the project root directory (may be null to skip project-level)
 36	     * @return a catalog with all loaded definitions
 37	     */
 38	    public static AgentCatalog loadAll(Path projectRoot) {
 39	        AgentCatalog catalog = new AgentCatalog();
 40	
 41	        // Layer 1: Built-in (classpath)
 42	        loadBuiltins(catalog);
 43	
 44	        // Layer 2: User-level (~/.mewcode/agents/)
 45	        String home = System.getProperty("user.home");
 46	        if (home != null && !home.isEmpty()) {
 47	            loadDir(catalog, Path.of(home, ".mewcode", "agents"), "user");
 48	        }
 49	
 50	        // Layer 3: Project-level (<root>/.mewcode/agents/)
 51	        if (projectRoot != null) {
 52	            loadDir(catalog, projectRoot.resolve(".mewcode").resolve("agents"), "project");
 53	        }
 54	
 55	        // Layer 4: Plugin-level — reserved, always empty in this release
 56	
 57	        return catalog;
 58	    }
 59	
 60	    // ── Built-in loading ──────────────────────────────────────────────────
 61	
 62	    private static void loadBuiltins(AgentCatalog catalog) {
 63	        try {
 64	            Enumeration<URL> resources = AgentLoader.class.getClassLoader()
 65	                    .getResources("subagent/builtin");
 66	            while (resources.hasMoreElements()) {
 67	                URL dirUrl = resources.nextElement();
 68	                if ("file".equals(dirUrl.getProtocol())) {
 69	                    Path dir = Path.of(dirUrl.toURI());
 70	                    loadDir(catalog, dir, "builtin");
 71	                } else {
 72	                    // Inside JAR: scan via classpath listing
 73	                    loadBuiltinsFromClasspath(catalog);
 74	                }
 75	            }
 76	        } catch (Exception e) {
 77	            // Try fallback: load builtins from classpath by name
 78	            loadBuiltinsFromClasspath(catalog);
 79	        }
 80	    }
 81	
 82	    private static void loadBuiltinsFromClasspath(AgentCatalog catalog) {
 83	        // Load the three known built-in agents by name
 84	        for (String name : List.of("general-purpose", "explore", "plan")) {
 85	            String resourcePath = "/subagent/builtin/" + name + ".md";
 86	            try (InputStream in = AgentLoader.class.getResourceAsStream(resourcePath)) {
 87	                if (in != null) {
 88	                    String content = new String(in.readAllBytes(), java.nio.charset.StandardCharsets.UTF_8);
 89	                    SubAgentSpec spec = parseContent(content, resourcePath);
 90	                    catalog.register(spec);
 91	                }
 92	            } catch (Exception e) {
 93	                throw new RuntimeException(
 94	                        "Failed to load built-in agent definition: " + resourcePath, e);
 95	            }
 96	        }
 97	    }
 98	
 99	    // ── Directory loading ─────────────────────────────────────────────────
100	
101	    private static void loadDir(AgentCatalog catalog, Path dir, String source) {
102	        if (!Files.isDirectory(dir)) {
103	            return;
104	        }
105	        try (DirectoryStream<Path> stream = Files.newDirectoryStream(dir, "*.md")) {
106	            for (Path path : stream) {
107	                if (Files.isDirectory(path)) continue;
108	                try {
109	                    String content = Files.readString(path);
110	                    SubAgentSpec spec = parseContent(content, path.toString());
111	                    catalog.register(spec);
112	                } catch (IllegalArgumentException e) {
113	                    System.err.println("[AgentLoader] 警告: " + e.getMessage() + " — 跳过");
114	                } catch (Exception e) {
115	                    System.err.println("[AgentLoader] 警告: 无法解析 " + path + ": "
116	                            + e.getMessage() + " — 跳过");
117	                }
118	            }
119	        } catch (IOException e) {
120	            // Directory unreadable — skip silently
121	        }
122	    }
123	
124	    // ── Parsing ───────────────────────────────────────────────────────────
125	
126	    /**
127	     * Parse a single agent definition file content.
128	     */
129	    static SubAgentSpec parseContent(String content, String source) {
130	        String trimmed = content.strip();
131	
132	        String yamlBlock = null;
133	        String body = trimmed;
134	
135	        if (trimmed.startsWith("---")) {
136	            int firstEnd = trimmed.indexOf("---", 3);
137	            if (firstEnd >= 0) {
138	                yamlBlock = trimmed.substring(3, firstEnd).strip();
139	                body = trimmed.substring(firstEnd + 3).strip();
140	            }
141	        }
142	
143	        if (yamlBlock == null || yamlBlock.isEmpty()) {
144	            throw new IllegalArgumentException(
145	                    "Agent definition " + source + ": missing YAML frontmatter (---)");
146	        }
147	
148	        Map<String, Object> frontmatter;
149	        try {
150	            @SuppressWarnings("unchecked")
151	            Map<String, Object> raw = YAML.readValue(yamlBlock, Map.class);
152	            frontmatter = raw != null ? raw : Map.of();
153	        } catch (Exception e) {
154	            throw new IllegalArgumentException(
155	                    "Agent definition " + source + ": invalid YAML frontmatter: " + e.getMessage());
156	        }
157	
158	        // Required fields
159	        String name = getString(frontmatter, "name");
160	        if (name == null || name.isEmpty()) {
161	            throw new IllegalArgumentException(
162	                    "Agent definition " + source + ": missing required field 'name'");
163	        }
164	        if (!name.matches("[a-z0-9-]{1,32}")) {
165	            throw new IllegalArgumentException(
166	                    "Agent definition " + source + ": invalid name '" + name
167	                            + "' (must be [a-z0-9-]{1,32})");
168	        }
169	
170	        String description = getString(frontmatter, "description");
171	        if (description == null || description.isEmpty()) {
172	            throw new IllegalArgumentException(
173	                    "Agent definition " + source + ": missing required field 'description'");
174	        }
175	
176	        // Optional fields
177	        List<String> tools = getStringList(frontmatter, "tools");
178	        List<String> disallowedTools = getStringList(frontmatter, "disallowedTools");
179	        String model = getString(frontmatter, "model");
180	        String permissionMode = getString(frontmatter, "permissionMode");
181	        int maxTurns = getInt(frontmatter, "maxTurns", 0);
182	        boolean background = getBoolean(frontmatter, "background", false);
183	
184	        // Validate enums
185	        if (model != null && !model.isEmpty() && !"inherit".equals(model)
186	                && !SubAgentSpec.VALID_MODELS.contains(model)) {
187	            System.err.println("[AgentLoader] 警告: " + source + ": unknown model '"
188	                    + model + "', fallback to 'inherit'");
189	            model = null;
190	        }
191	
192	        if (permissionMode != null && !permissionMode.isEmpty()
193	                && !SubAgentSpec.VALID_PERMISSION_MODES.contains(permissionMode)) {
194	            System.err.println("[AgentLoader] 警告: " + source + ": unknown permissionMode '"
195	                    + permissionMode + "', fallback to 'default'");
196	            permissionMode = null;
197	        }
198	
199	        String systemPrompt = body.isEmpty() ? null : body;
200	
201	        return SubAgentSpec.of(name, description, tools, disallowedTools,
202	                systemPrompt, maxTurns, model, permissionMode, background);
203	    }
