 1	package com.mewcode.subagent;
 2	
 3	import java.util.HashSet;
 4	import java.util.List;
 5	import java.util.Set;
 6	import java.util.function.Predicate;
 7	
 8	/**
 9	 * Filters tool names to produce a restricted set suitable for a sub-agent.
10	 */
11	public final class ToolFilter {
12	
13	    /** Tools that are never available to definition-based sub-agents. */
14	    static final Set<String> ALL_AGENT_DISALLOWED_TOOLS = Set.of("Agent");
15	
16	    /** Reserved for future use — custom-agent specific blocks. */
17	    static final Set<String> CUSTOM_AGENT_DISALLOWED_TOOLS = Set.of();
18	
19	    /** Tools permitted for async (background) definition-based sub-agents. */
20	    static final Set<String> ASYNC_ALLOWED_TOOLS = Set.of(
21	            "read_file", "write_file", "edit_file", "glob", "grep",
22	            "execute_command", "Skill", "ToolSearch"
23	    );
24	
25	    private ToolFilter() {}
26	
27	    /**
28	     * Build a tool-name predicate for a sub-agent.
29	     *
30	     * @param spec    the sub-agent specification
31	     * @param isAsync whether this is a background/async execution
32	     * @param isFork  whether this is a fork (skips global-disallow + async-whitelist)
33	     * @return a predicate that returns true for allowed tool names
34	     */
35	    public static Predicate<String> buildFilter(SubAgentSpec spec, boolean isAsync, boolean isFork) {
36	        Set<String> disallowed = new HashSet<>(spec.disallowedTools());
37	
38	        boolean hasWhitelist = spec.tools() != null && !spec.tools().isEmpty()
39	                && !(spec.tools().size() == 1 && "*".equals(spec.tools().getFirst()));
40	        Set<String> allowed = hasWhitelist ? new HashSet<>(spec.tools()) : Set.of();
41	
42	        return name -> {
43	            // Layer 1: MCP tools always pass through
44	            if (isMcpTool(name)) {
45	                return !disallowed.contains(name); // unless explicitly blacklisted
46	            }
47	
48	            // Layer 2: Globally blocked tools (definition-based only)
49	            if (!isFork && ALL_AGENT_DISALLOWED_TOOLS.contains(name)) {
50	                return false;
51	            }
52	
53	            // Layer 3: Async whitelist (definition-based background only; Fork skips)
54	            if (isAsync && !isFork) {
55	                if (!ASYNC_ALLOWED_TOOLS.contains(name) && !isMcpTool(name)) {
56	                    return false;
57	                }
58	            }
59	
60	            // Layer 4: Per-spec disallowed tools
61	            if (disallowed.contains(name)) {
62	                return false;
63	            }
64	
65	            // Layer 5: Per-spec whitelist intersection
66	            return !hasWhitelist || allowed.contains(name);
67	        };
68	    }
69	
70	    /**
71	     * Build a filter for a definition-based foreground sub-agent.
72	     */
73	    public static Predicate<String> buildFilter(SubAgentSpec spec) {
74	        return buildFilter(spec, false, false);
75	    }
76	
77	    /**
78	     * Build a filter for a fork sub-agent (always background, inherits parent tools).
79	     */
80	    public static Predicate<String> buildForkFilter() {
81	        return buildFilter(SubAgentSpec.FORK, true, true);
82	    }
83	
84	    private static boolean isMcpTool(String name) {
85	        return name.startsWith("mcp__");
86	    }
87	}

