368	    private AgentLoop createSubAgent(ConversationManager conv, SubAgentSpec spec,
369	                                      Predicate<String> toolFilter,
370	                                      String modelOverride, String name,
371	                                      String workDir) {
372	        // Create event queue
373	        BlockingQueue<com.mewcode.agent.AgentEvent> eventQueue = new LinkedBlockingQueue<>(256);
374	
375	        int effMaxTurns = spec.effectiveMaxTurns(globalMaxTurns);
376	        String permMode = spec.effectivePermissionMode();
377	
378	        AgentLoop agent = new AgentLoop(
379	                provider,
380	                toolRegistry,
381	                conv,
382	                eventQueue,
383	                effMaxTurns,
384	                streamTimeoutSeconds,
385	                permissionChecker
386	        );
387	        agent.setPlanMode("plan".equals(permMode));
388	        agent.setWorkingDirectory(workDir != null ? workDir : workingDirectory);
389	        agent.setToolFilter(toolFilter);
390	
391	        // Configure as sub-agent
392	        String displayName = name != null ? name : spec.name();
393	        agent.configureAsSubAgent(displayName, spec.systemPromptOverride(),
394	                effMaxTurns, permMode);
395	
396	        return agent;
397	    }
