925	    /**
926	     * Run this AgentLoop to completion synchronously and return the final output text.
927	     */
928	    public String runToCompletion() {
929	        var output = new StringBuilder();
930	        boolean hadError = false;
931	        String errorMsg = "";
932	
933	        // Start the agent loop on a virtual thread
934	        Thread loopThread = Thread.startVirtualThread(this);
935	        long startTime = System.currentTimeMillis();
936	        long timeoutMs = isSubAgent ? subAgentTimeoutMs : streamTimeoutMs;
937	
938	        try {
939	            while (true) {
940	                AgentEvent event;
941	                try {
942	                    long remaining;
943	                    if (timeoutMs > 0) {
944	                        remaining = timeoutMs - (System.currentTimeMillis() - startTime);
945	                        if (remaining <= 0) {
946	                            errorMsg = "Sub-agent timed out after " + (timeoutMs / 1000) + "s";
947	                            break;
948	                        }
949	                    } else {
950	                        remaining = 60_000; // no timeout — poll with 60s idle window
951	                    }
952	                    event = eventQueue.poll(Math.min(remaining, 30000), TimeUnit.MILLISECONDS);
953	                } catch (InterruptedException e) {
954	                    Thread.currentThread().interrupt();
955	                    errorMsg = "Sub-agent was interrupted";
956	                    break;
957	                }
958	
959	                if (event == null) {
960	                    continue; // poll timeout, not an error
961	                }
962	
963	                switch (event.getType()) {
964	                    case TEXT_DELTA -> {
965	                        if (event.getText() != null) {
966	                            // 只收集实际输出文本，排除思考过程
967	                            var ct = event.getChunkType();
968	                            if (ct == null || ct == com.mewcode.provider.ChunkType.TEXT) {
969	                                output.append(event.getText());
970	                            }
971	                        }
972	                    }
973	                    case ERROR -> {
974	                        hadError = true;
975	                        errorMsg = event.getMessage() != null ? event.getMessage() : "Unknown error";
976	                    }
977	                    case LOOP_FINISHED -> {
978	                        return output.toString().trim();
979	                    }
980	                    case CANCELLED -> {
981	                        hadError = true;
982	                        errorMsg = "Sub-agent was cancelled";
983	                    }
984	                    default -> {
985	                        // TOOL_CALL_START, TOOL_CALL_RESULT, PROGRESS, COMPACT,
986	                        // TOKEN_USAGE, PERMISSION_REQUIRED, MEMORY_TICK — consume silently
987	                    }
988	                }
989	
990	                if (hadError) break;
991	            }
992	        } finally {
993	            cancelled = true;
994	        }
995	
996	        return "[sub-agent error] " + errorMsg;
997	
998	    }
999	}

