460	    @Override
461	    public void run() {
462	        // Clear loop-scoped rules from the previous run
463	        permissionChecker.getRuleEngine().clearLoopRules();
464	
465	        offerEvent(AgentEvent.of(AgentEventType.LOOP_STARTED).build());
466	
467	        // ---- hook: session_start ----
468	        if (hookEngine != null) {
469	            hookEngine.runHooks(EventName.SESSION_START, HookContext.of(EventName.SESSION_START));
470	        }
471	
472	        try {
473	            for (int iter = 0; iter < maxIterations; iter++) {
474	                // ---- check cancellation ----
475	                if (cancelled) {
476	                    offerEvent(AgentEvent.of(AgentEventType.CANCELLED)
477	                            .message("用户取消").build());
478	                    return;
479	                }
480	
481	                // ---- progress ----
482	                offerEvent(AgentEvent.of(AgentEventType.PROGRESS)
483	                        .message("第 " + (iter + 1) + "/" + maxIterations + " 轮").build());
484	
485	                // ---- drain task notifications ----
486	                if (notificationFn != null) {
487	                    for (String note : notificationFn.get()) {
488	                        conversation.addSystemReminder(note);
489	                    }
490	                }
491	
492	                // ---- hook: turn_start ----
493	                if (hookEngine != null) {
494	                    hookEngine.runHooks(EventName.TURN_START, HookContext.of(EventName.TURN_START));
495	                }
496	
497	                // ---- context compaction ----
498	
499	                // Inject active skills into conversation (per-turn)
500	                if (!activeSkills.isEmpty()) {
501	                    conversation.setActiveSkillsContent(getActiveSkillsContext());
502	                }
503	
504	                // Build tool schemas for this iteration (for Layer 2 recovery attachment)
505	                List<Map<String, Object>> toolSchemas = buildToolSchemas();
506	
507	                // Layer 2: Auto-compact check (runs FIRST — may replace conversation in-place)
508	                String compactMsg = ContextCompactor.manage(
509	                        conversation, provider, contextWindow, workingDirectory,
510	                        compactTracking, recoveryState, toolSchemas);
511	                if (!compactMsg.isEmpty()) {
512	                    offerEvent(AgentEvent.compactEvent(compactMsg));
513	                }
514	
515	                // Layer 1: Apply tool-result budget (runs AFTER Layer 2 — reads from
516	                // the possibly-compacted conversation, returns a fresh apiConv)
517	                Path sessionDir = Paths.get(workingDirectory, ".mewcode", "session_save_content",
518	                        sessionId != null ? sessionId : "_unknown");
519	                ApplyResult applied = ToolResultBudget.apply(conversation, sessionDir, replacementState);
520	                if (!applied.newRecords().isEmpty()) {
521	                    try {
522	                        ReplacementRecordsIO.append(sessionDir, applied.newRecords());
523	                    } catch (Exception ignored) {
524	                        // Best-effort transcript persistence
525	                    }
526	                    // Log Layer 1 activity
527	                    int spilled = 0, snipped = 0;
528	                    for (var r : applied.newRecords()) {
529	                        if (r.replacement().startsWith("[Result of ")) spilled++;
530	                        else if (r.replacement().startsWith("[Stale output snipped:")) snipped++;
531	                    }
532	                    if (spilled > 0 || snipped > 0) {
533	                        var parts = new ArrayList<String>();
534	                        if (spilled > 0) parts.add(String.format("spilled %d tool result(s)", spilled));
535	                        if (snipped > 0) parts.add(String.format("snipped %d stale result(s)", snipped));
536	                        offerEvent(AgentEvent.compactEvent(String.join("; ", parts)));
537	                    }
538	                }
539	
540	                // ---- call LLM ----
541	                StreamingCollector collector = new StreamingCollector(eventQueue);
542	                List<Tool> activeTools = planMode
543	                        ? toolRegistry.getReadOnlyTools()
544	                        : toolRegistry.getAllTools();
545	
546	                if (activeTools.isEmpty() && planMode) {
547	                    activeTools = toolRegistry.getAllTools();
548	                }
549	
550	                // ---- hook: pre_send ----
551	                if (hookEngine != null) {
552	                    hookEngine.runHooks(EventName.PRE_SEND,
553	                            HookContext.ofMessage(EventName.PRE_SEND, "Sending API request (turn " + (iter + 1) + ")"));
554	                }
555	
556	                // Use cleaned messages from Layer 1 for the API call
557	                List<Message> apiMessages = applied.apiConv().getMessages(iter, planMode);
558	                provider.streamChat(apiMessages, collector, activeTools);
559	
560	                boolean completed = collector.awaitCompletion(streamTimeoutMs);
561	
562	                // ---- hook: post_receive ----
563	                if (hookEngine != null) {
564	                    hookEngine.runHooks(EventName.POST_RECEIVE,
565	                            HookContext.ofMessage(EventName.POST_RECEIVE, "Received API response (turn " + (iter + 1) + ")"));
566	                }
567	
568	                if (!completed) {
569	                    offerEvent(AgentEvent.of(AgentEventType.ERROR)
570	                            .message("LLM 流超时（" + (streamTimeoutMs / 1000) + " 秒）").build());
571	                    return;
572	                }
573	
574	                // ---- check stream error ----
575	                Throwable streamErr = collector.getError();
576	                if (streamErr != null) {
577	                    String errMsg = streamErr.getMessage() != null ? streamErr.getMessage() : "";
578	                    // Context-too-long recovery
579	                    if ((errMsg.contains("context") || errMsg.contains("too long")
580	                            || errMsg.contains("prompt"))
581	                            && compactTracking.isTripped()) {
582	                        try {
583	                            forceCompact();
584	                        } catch (Exception ignored) {}
585	                        continue;
586	                    }
587	                    return;
588	                }
589	
590	                // ---- emit token usage ----
591	                int inputTokens = collector.getInputTokens();
592	                int outputTokens = collector.getOutputTokens();
593	                long cacheCreate = collector.getCacheCreationTokens();
594	                long cacheRead = collector.getCacheReadTokens();
595	                if (inputTokens > 0 || outputTokens > 0 || cacheCreate > 0 || cacheRead > 0) {
596	                    offerEvent(AgentEvent.of(AgentEventType.TOKEN_USAGE)
597	                            .cacheCreationTokens(cacheCreate)
598	                            .cacheReadTokens(cacheRead)
599	                            .build());
600	                }
601	
602	                // ---- check stop reason ----
603	                StopReason stopReason = StopReason.fromString(collector.getStopReason());
604	                if (stopReason != StopReason.TOOL_USE) {
605	                    String finalText = collector.getFullText().trim();
606	                    if (!finalText.isEmpty()) {
607	                        conversation.addAssistantMessage(finalText);
608	                        // Save assistant message to session JSONL
609	                        if (workingDirectory != null && sessionId != null) {
610	                            SessionManager.saveMessage(workingDirectory, sessionId,
611	                                    "assistant", finalText);
612	                        }
613	                    }
614	                    // ---- memory extraction tick ----
615	                    offerEvent(AgentEvent.of(AgentEventType.MEMORY_TICK).build());
616	                    if (memoryExtractor != null && memoryManager != null
617	                            && memoryManager.shouldExtract() && providerForMemory != null) {
618	                        memoryExtractor.extractAsync(providerForMemory, conversation, memoryManager);
619	                    }
620	                    offerEvent(AgentEvent.of(AgentEventType.LOOP_FINISHED).build());
621	                    return;
622	                }
623	
624	                // ---- model wants tools — validate them ----
625	                List<ToolCall> toolCalls = collector.getToolCalls();
626	
627	                if (toolCalls.isEmpty()) {
628	                    String text = collector.getFullText().trim();
629	                    if (!text.isEmpty()) {
630	                        conversation.addAssistantMessage(text);
631	                    }
632	                    offerEvent(AgentEvent.of(AgentEventType.LOOP_FINISHED).build());
633	                    return;
634	                }
635	
636	                // Check for unknown tools
637	                for (ToolCall tc : toolCalls) {
638	                    if (toolRegistry.get(tc.getName()) == null) {
639	                        offerEvent(AgentEvent.of(AgentEventType.UNKNOWN_TOOL)
640	                                .toolName(tc.getName())
641	                                .callId(tc.getId())
642	                                .message("未知工具: " + tc.getName()).build());
643	                        return;
644	                    }
645	                }
646	
647	                // ---- add tool_use message to conversation ----
648	                conversation.addToolCallMessage(collector.getFullText().trim(), toolCalls);
649	                // Save to session JSONL (with tool_use metadata for reliable recovery)
650	                if (workingDirectory != null && sessionId != null) {
651	                    List<String> toolUseIds = toolCalls.stream()
652	                            .map(ToolCall::getId).toList();
653	                    List<String> toolNames = toolCalls.stream()
654	                            .map(ToolCall::getName).toList();
655	                    SessionManager.saveMessage(workingDirectory, sessionId,
656	                            "assistant", collector.getFullText().trim(),
657	                            null, false, toolUseIds, toolNames);
658	                }
659	
660	                // ---- permission pre-check ----
661	                List<ToolCall> executableCalls = new ArrayList<>();
662	                Map<Integer, ToolResult> preResolved = new LinkedHashMap<>();
663	
664	                for (int i = 0; i < toolCalls.size(); i++) {
665	                    ToolCall toolCall = toolCalls.get(i);
666	                    Tool tool = toolRegistry.get(toolCall.getName());
667	                    PermissionResult permissionResult = permissionChecker.check(tool, toolCall.getInput());
668	
669	                    // Sub-agent permission mode override
670	                    if (isSubAgent) {
671	                        permissionResult = adjustForSubAgentMode(permissionResult, tool);
672	                    }
673	
674	                    switch (permissionResult.getDecision()) {
675	                        case ALLOW -> executableCalls.add(toolCall);
676	                        case DENY -> preResolved.put(i, new ToolResult(false,
677	                                "权限拒绝: " + permissionResult.getReason() + "\n提示: " + permissionResult.getHint(),
678	                                "PERMISSION_DENIED"));
679	                        case ASK -> {
680	                            // Blocking human-in-the-loop
681	                            PermissionResponse userDecision = waitForPermission(toolCall, permissionResult);
682	                            if (userDecision == PermissionResponse.ALLOW
683	                                    || userDecision == PermissionResponse.ALLOW_ALWAYS) {
684	                                executableCalls.add(toolCall);
685	                                // Add rule for future calls
686	                                String keyParam = PermissionChecker.extractContent(toolCall.getName(), toolCall.getInput());
687	                                if (keyParam == null) {
688	                                    keyParam = toolCall.getName(); // fallback: tool-level wildcard
689	                                }
690	                                String escapedKey = RuleEngine.escapeGlob(keyParam);
691	                                if (userDecision == PermissionResponse.ALLOW_ALWAYS) {
692	                                    // Session-scoped "don't ask again"
693	                                    permissionChecker.addAllowAlways(toolCall.getName(), keyParam);
694	                                } else {
695	                                    // One-time — loop scope
696	                                    permissionChecker.getRuleEngine().addLoopRule(
697	                                            new RuleEntry(toolCall.getName(), escapedKey, RuleEntry.RuleEffect.ALLOW));
698	                                }
699	                            } else {
700	                                preResolved.put(i, new ToolResult(false,
701	                                        "用户拒绝此项操作",
702	                                        "PERMISSION_DENIED"));
703	                            }
704	                        }
705	                    }
706	                }
707	
708	                // ---- pre_tool_use hook interception (before execute, after permission) ----
709	                for (int i = 0; i < toolCalls.size(); i++) {
710	                    if (preResolved.containsKey(i)) continue; // already denied by permission
711	                    ToolCall toolCall = toolCalls.get(i);
712	                    if (hookEngine != null) {
713	                        PreToolResult preToolResult = hookEngine.runPreToolHooks(toolCall.getName(), toolCall.getInput());
714	                        if (preToolResult.rejected()) {
715	                            preResolved.put(i, new ToolResult(false, preToolResult.message(), "HOOK_REJECTED"));
716	                        }
717	                    }
718	                }
719	
720	                // Rebuild executableCalls excluding hook-rejected ones
721	                executableCalls = new ArrayList<>();
722	                for (int i = 0; i < toolCalls.size(); i++) {
723	                    if (!preResolved.containsKey(i)) {
724	                        executableCalls.add(toolCalls.get(i));
725	                    }
726	                }
727	
728	                // ---- execute tools (read-only concurrent, side-effects sequential) ----
729	                List<ToolResult> execResults = executionStrategy.execute(executableCalls, toolRegistry);
730	
731	                // ---- record file reads for compaction recovery ----
732	                for (int i = 0; i < executableCalls.size(); i++) {
733	                    ToolCall tc = executableCalls.get(i);
734	                    // Index into execResults matches executableCalls order
735	                    if (i < execResults.size()) {
736	                        ToolResult result = execResults.get(i);
737	                        if (result.isSuccess() && isFileReadingTool(tc.getName())) {
738	                            String path = extractPath(tc);
739	                            if (path != null) {
740	                                recoveryState.recordFileRead(path, result.getContent());
741	                            }
742	                        }
743	                    }
744	                }
745	
746	                // ---- merge results in original order ----
747	                List<ToolResult> results = new ArrayList<>(toolCalls.size());
748	                int execIdx = 0;
749	                for (int i = 0; i < toolCalls.size(); i++) {
750	                    if (preResolved.containsKey(i)) {
751	                        results.add(preResolved.get(i));
752	                    } else {
753	                        results.add(execResults.get(execIdx++));
754	                    }
755	                }
756	
757	                // ---- push results to UI and conversation (batched into one message) ----
758	                List<ToolResultBlock> resultBlocks = new ArrayList<>();
759	                for (int i = 0; i < toolCalls.size(); i++) {
760	                    ToolCall tc = toolCalls.get(i);
761	                    ToolResult result = results.get(i);
762	
763	                    offerEvent(AgentEvent.of(AgentEventType.TOOL_CALL_RESULT)
764	                            .toolName(tc.getName())
765	                            .callId(tc.getId())
766	                            .toolResult(result)
767	                            .build());
768	
769	                    // ---- hook: post_tool_use ----
770	                    if (hookEngine != null) {
771	                        hookEngine.runHooks(EventName.POST_TOOL_USE,
772	                                HookContext.ofTool(EventName.POST_TOOL_USE, tc.getName(), tc.getInput()));
773	                    }
774	
775	                    resultBlocks.add(new ToolResultBlock(tc.getId(), result.getContent(), !result.isSuccess()));
776	                }
777	                conversation.addToolResultsMessage(resultBlocks);
778	
779	                // Persist tool_results to session JSONL so /resume can
780	                // reconstruct the full tool-call chain.
781	                if (workingDirectory != null && sessionId != null) {
782	                    for (ToolResultBlock block : resultBlocks) {
783	                        SessionManager.saveMessage(workingDirectory, sessionId,
784	                                "tool_result", block.content(), block.toolUseId(), block.isError());
785	                    }
786	                }
787	
788	                // ---- hook: turn_end ----
789	                if (hookEngine != null) {
790	                    hookEngine.runHooks(EventName.TURN_END, HookContext.of(EventName.TURN_END));
791	                }
792	            }
793	
794	            // Hit iteration limit
795	            offerEvent(AgentEvent.of(AgentEventType.ERROR)
796	                    .message("已达迭代上限（" + maxIterations + " 轮），循环终止").build());
797	
798	        } catch (Exception e) {
799	            offerEvent(AgentEvent.of(AgentEventType.ERROR)
800	                    .message("Agent Loop 异常: " + e.getMessage()).build());
801	        } finally {
802	            // ---- hook: session_end (fires on ALL exit paths) ----
803	            if (hookEngine != null) {
804	                hookEngine.runHooks(EventName.SESSION_END, HookContext.of(EventName.SESSION_END));
805	            }
806	        }
807	    }
