823	    private List<Map<String, Object>> buildToolSchemas() {
824	        List<Tool> activeTools = planMode
825	                ? toolRegistry.getReadOnlyTools()
826	                : toolRegistry.getAllTools();
827	        if (activeTools.isEmpty() && planMode) {
828	            activeTools = toolRegistry.getAllTools();
829	        }
830	
831	        // Apply skill tool filter (Skill tool always passes through)
832	        if (skillToolFilter != null) {
833	            activeTools = activeTools.stream()
834	                    .filter(t -> "Skill".equals(t.getName()) || skillToolFilter.test(t.getName()))
835	                    .toList();
836	        }
837	
838	        return toolRegistry.toApiFormat(activeTools);
839	    }
