399	    // ── Background launch ───
400	
401	    private ToolResult launchBackgroundTask(AgentLoop subAgent, SubAgentSpec spec, String description, String name,
402	                                            AgentWorktree.Result worktreeResult) {
403	
404	        String taskName = name != null ? name : description;
405	        String taskId = taskManager.createTask(taskName);
406	
407	        Thread thread = Thread.startVirtualThread(() -> {
408	            taskManager.setRunning(taskId, Thread.currentThread());
409	            try {
410	                String result = subAgent.runToCompletion();
411	
412	                // Worktree cleanup after background completion
413	                if (worktreeResult != null) {
414	                    result = appendWorktreeInfo(result, worktreeResult);
415	                }
416	
417	                taskManager.setCompleted(taskId, result);
418	            } catch (Exception e) {
419	                taskManager.setFailed(taskId, "Sub-agent error: " + e.getMessage());
420	                // Best-effort cleanup on failure
421	                if (worktreeResult != null) {
422	                    AgentWorktree.remove(worktreeResult.worktreePath(),
423	                            worktreeResult.worktreeBranch(), worktreeResult.gitRoot());
424	                }
425	            }
426	        });
427	
428	        taskManager.setRunning(taskId, thread);
429	
430	        return new ToolResult(true,
431	                "{\"task_id\": \"" + taskId + "\", \"status\": \"async_launched\", "
432	                        + "\"description\": \"" + escapeJson(description) + "\", "
433	                        + "\"hint\": \"任务完成后会自动通知你，无需轮询 TaskGet/TaskList\"}");
434	    }
