436	    // ── Sync with timeout ─────────────────────────────────────────────────
437	
438	    private ToolResult runWithTimeout(AgentLoop subAgent, SubAgentSpec spec,
439	                                       String description, String prompt, String name,
440	                                       AgentWorktree.Result wtResult) {
441	        String taskName = name != null ? name : ("sync-" + spec.name());
