 14	/**
 15	 * Dual-path stream collector: pushes events to the UI queue in real time while
 16	 * accumulating the full response (text, tool calls, stop reason) for the Agent
 17	 * Loop to make continuation decisions.
 18	 */
 19	public class StreamingCollector implements StreamCallback {
 20	
 21	    private static final ObjectMapper JSON = new ObjectMapper();
 22	
 23	    private final BlockingQueue<AgentEvent> eventQueue;
 24	    private final CountDownLatch doneLatch = new CountDownLatch(1);
 25	
 26	    private final StringBuilder fullText = new StringBuilder();
 27	    private final List<ToolCall> toolCalls = new ArrayList<>();
 28	    private String stopReason;
 29	    private Throwable error;
 30	
 31	    // ---- per-request token usage ----
 32	    private int inputTokens;
 33	    private int outputTokens;
 34	    private long cacheCreationTokens;
 35	    private long cacheReadTokens;
 36	
 37	    public StreamingCollector(BlockingQueue<AgentEvent> eventQueue) {
 38	        this.eventQueue = eventQueue;
 39	    }
 40	
 41	    // ---- StreamCallback implementation ----
 42	
 43	    @Override
 44	    public void onChunk(String text, ChunkType type) {
 45	        if (type == ChunkType.TOOL_CALL) {
 46	            try {
 47	                ToolCall tc = JSON.readValue(text, ToolCall.class);
 48	                toolCalls.add(tc);
 49	                // Push TOOL_CALL_START to UI
 50	                offerEvent(AgentEvent.of(AgentEventType.TOOL_CALL_START)
 51	                        .toolName(tc.getName())
 52	                        .callId(tc.getId())
 53	                        .build());
 54	            } catch (Exception e) {
 55	                // Malformed tool call — shouldn't happen with AnthropicProvider
 56	            }
 57	        } else {
 58	            // TEXT, THINKING, ERROR — push to UI and accumulate text
 59	            offerEvent(AgentEvent.of(AgentEventType.TEXT_DELTA)
 60	                    .text(text)
 61	                    .chunkType(type)
 62	                    .build());
 63	            if (type == ChunkType.TEXT) {
 64	                fullText.append(text);
 65	            }
 66	        }
 67	    }
 68	
 69	    @Override
 70	    public void onComplete(String stopReason) {
 71	        this.stopReason = stopReason;
 72	        doneLatch.countDown();
 73	    }
 74	
 75	    @Override
 76	    public void onUsage(int inputTokens, int outputTokens,
 77	                        long cacheCreationTokens, long cacheReadTokens) {
 78	        this.inputTokens = inputTokens;
 79	        this.outputTokens = outputTokens;
 80	        this.cacheCreationTokens = cacheCreationTokens;
 81	        this.cacheReadTokens = cacheReadTokens;
 82	    }
 83	
 84	    @Override
 85	    public void onError(Throwable t) {
 86	        this.error = t;
 87	        offerEvent(AgentEvent.of(AgentEventType.ERROR)
 88	                .message(t.getMessage())
 89	                .build());
 90	        doneLatch.countDown();
 91	    }
