 93	    // ---- blocking wait for the Agent Loop ----
 94	
 95	    /**
 96	     * Block until the stream completes or times out.
 97	     *
 98	     * @param timeoutMs max wait time in milliseconds
 99	     * @return true if completed, false if timed out
100	     */
101	    public boolean awaitCompletion(long timeoutMs) {
102	        try {
103	            return doneLatch.await(timeoutMs, TimeUnit.MILLISECONDS);
104	        } catch (InterruptedException e) {
105	            Thread.currentThread().interrupt();
106	            return false;
107	        }
108	    }
109	
110	    // ---- getters for the Agent Loop ----
111	
112	    public String getFullText() {
113	        return fullText.toString();
114	    }
115	
116	    public List<ToolCall> getToolCalls() {
117	        return toolCalls; // caller must not mutate
118	    }
119	
120	    public String getStopReason() {
121	        return stopReason;
122	    }
123	
124	    public Throwable getError() {
125	        return error;
126	    }
127	
128	    public int getInputTokens() { return inputTokens; }
129	
