131	
132	    public long getCacheCreationTokens() { return cacheCreationTokens; }
133	
134	    public long getCacheReadTokens() { return cacheReadTokens; }
135	
136	    // ---- internal ----
137	
138	    private void offerEvent(AgentEvent event) {
139	        try {
140	            eventQueue.put(event);
141	        } catch (InterruptedException e) {
142	            Thread.currentThread().interrupt();
143	        }
144	    }
