165	    @Override
166	    public ToolResult execute(Map<String, Object> args) {
167	        String description = getString(args, "description");
168	        String prompt = getString(args, "prompt");
169	        if (description == null || description.isEmpty() || prompt == null || prompt.isEmpty()) {
170	            return new ToolResult(false,
171	                    "Error: description 和 prompt 参数均为必填", "MISSING_PARAM");
172	        }
173	
174	        String subagentType = getString(args, "subagent_type");
175	        String modelOverride = getString(args, "model");
176	        String name = getString(args, "name");
177	        String isolation = getString(args, "isolation");
178	        boolean runInBackground = Boolean.TRUE.equals(args.get("run_in_background"));
179	
180	        // ── Fork path (no subagent_type) ──────────────────────────────────
181	        if (subagentType == null || subagentType.isEmpty()) {
182	            return executeFork(description, prompt, modelOverride, name, isolation);
183	        }
184	
185	        // ── Definition-based path ─────────────────────────────────────────
186	        SubAgentSpec spec = catalog.resolve(subagentType);
187	        if (spec == null) {
188	            String available = String.join(", ", catalog.listNames());
189	            return new ToolResult(false,
190	                    "未知 subagent_type: '" + subagentType + "'。可用类型: " + available,
191	                    "UNKNOWN_AGENT_TYPE");
192	        }
193	
194	        // Determine execution mode
195	        if (spec.background() || runInBackground) {
196	            if (!backgroundEnabled) {
197	                return new ToolResult(false,
198	                        "后台执行已禁用（配置 subagent.background.enabled: false）",
199	                        "BACKGROUND_DISABLED");
200	            }
201	            return executeBackground(spec, description, prompt, modelOverride, name, isolation);
202	        }
203	
204	        return executeSync(spec, description, prompt, modelOverride, isolation);
205	    }
