285	            } catch (Exception e) {
286	                return new ToolResult(false,
287	                        "Error creating agent worktree: " + e.getMessage(), "WORKTREE_FAILED");
288	            }
289	        }
290	
291	        String effectivePrompt = prompt;
292	        if (wtResult != null) {
293	            String notice = AgentWorktree.buildNotice(System.getProperty("user.dir"),
294	                    wtResult.worktreePath());
295	            effectivePrompt = notice + "\n\n" + effectivePrompt;
296	        }
297	
298	        ConversationManager subConv = new ConversationManager();
299	
300	        // Inject system prompt if specified
301	        if (spec.systemPromptOverride() != null && !spec.systemPromptOverride().isEmpty()) {
302	            subConv.getMessagesMutable().add(
303	                    new com.mewcode.conversation.Message("user",
304	                            "<system-reminder>\n" + spec.systemPromptOverride() + "\n</system-reminder>"));
