315	        AgentLoop subAgent = createSubAgent(subConv, spec, toolFilter, modelOverride, null, workDir);
316	
317	        // Run with auto-background timeout (and worktree cleanup on sync path)
318	        return runWithTimeout(subAgent, spec, description, effectivePrompt, null, wtResult);
