499	     *
500	     * @param config   the application configuration
501	     * @param registry the tool registry to register into
502	     * @param writer   the PrintWriter for output (from TerminalUI)
503	     * @return the McpManager (non-null even if no servers configured — it's a no-op manager)
504	     */
505	    private static McpManager initMcp(AppConfig config, ToolRegistry registry, java.io.PrintWriter writer) {
506	        AppConfig.McpConfigNode mcpConfig = config.getMcp();
507	        if (mcpConfig == null || mcpConfig.getServers() == null || mcpConfig.getServers().isEmpty()) {
508	            return null;
509	        }
510	        McpManager manager = new McpManager(mcpConfig.getServers());
511	        manager.registerAllMcpTools(registry, writer);
512	        return manager;
513	    }
