165	   165	    @Override
166	   166	    public ToolResult execute(Map<String, Object> args) {
167	   167	        String description = getString(args, "description");
168	   168	        String prompt = getString(args, "prompt");
169	   169	        if (description == null || description.isEmpty() || prompt == null || prompt.isEmpty()) {
170	   170	            return new ToolResult(false,
171	   171	                    "Error: description 和 prompt 参数均为必填", "MISSING_PARAM");
172	   172	        }
173	   173	
174	   174	        String subagentType = getString(args, "subagent_type");
175	   175	        String modelOverride = getString(args, "model");
176	   176	        String name = getString(args, "name");
177	   177	        String isolation = getString(args, "isolation");
178	   178	        boolean runInBackground = Boolean.TRUE.equals(args.get("run_in_background"));
179	   179	
180	   180	        // ── Fork path (no subagent_type) ──────────────────────────────────
181	   181	        if (subagentType == null || subagentType.isEmpty()) {
182	   182	            return executeFork(description, prompt, modelOverride, name, isolation);
183	   183	        }
184	   184	
185	   185	        // ── Definition-based path ─────────────────────────────────────────
186	   186	        SubAgentSpec spec = catalog.resolve(subagentType);
187	   187	        if (spec == null) {
188	   188	            String available = String.join(", ", catalog.listNames());
189	   189	            return new ToolResult(false,
190	   190	                    "未知 subagent_type: '" + subagentType + "'。可用类型: " + available,
191	   191	                    "UNKNOWN_AGENT_TYPE");
192	   192	        }
193	   193	
194	   194	        // Determine execution mode
195	   195	        if (spec.background() || runInBackground) {
196	   196	            if (!backgroundEnabled) {
197	   197	                return new ToolResult(false,
198	   198	                        "后台执行已禁用（配置 subagent.background.enabled: false）",
199	   199	                        "BACKGROUND_DISABLED");
200	   200	            }
201	   201	            return executeBackground(spec, description, prompt, modelOverride, name, isolation);
202	   202	        }
203	   203	
204	   204	        return executeSync(spec, description, prompt, modelOverride, isolation);
205	   205	    }
