207	   207	    // ── Fork execution ────────────────────────────────────────────────────
208	   208	
209	   209	    private ToolResult executeFork(String description, String prompt,
210	   210	                                    String modelOverride, String name, String isolation) {
211	   211	        if (!backgroundEnabled) {
212	   212	            return new ToolResult(false,
213	   213	                    "后台执行已禁用。Fork 路径需要后台执行，当前配置 subagent.background.enabled: false",
214	   214	                    "BACKGROUND_DISABLED");
215	   215	        }
216	   216	
217	   217	        if (parentConversation == null) {
218	   218	            return new ToolResult(false,
219	   219	                    "Error: Fork 需要父对话上下文（内部错误：parentConversation 未设置）",
220	   220	                    "NO_PARENT_CONV");
221	   221	        }
222	   222	
223	   223	        // Nested fork detection
224	   224	        if (ForkBuilder.containsForkBoilerplate(parentConversation)) {
225	   225	            return new ToolResult(false,
226	   226	                    "Fork 子 Agent 不能再启动 Agent（检测到嵌套 Fork）",
227	   227	                    "NESTED_FORK");
228	   228	        }
229	   229	
230	   230	        // Build forked conversation
231	   231	        ConversationManager forkedConversationManager = ForkBuilder.buildForkedConversation(parentConversation);
232	   232	
233	   233	        // Fork uses the FORK spec (no tool restrictions, background, maxTurns=50)
234	   234	        SubAgentSpec forkSpec = SubAgentSpec.FORK;
235	   235	
236	   236	        // Build fork filter: inherits parent tools, only blocks Agent at runtime
237	   237	        Predicate<String> forkFilter = ToolFilter.buildForkFilter();
238	   238	
239	   239	        // Worktree isolation for fork
240	   240	        AgentWorktree.Result wtResult = null;
241	   241	        if ("worktree".equals(isolation) && worktreeManager != null) {
242	   242	            String slug = generateWorktreeSlug();
243	   243	            try {
244	   244	                wtResult = AgentWorktree.create(slug, worktreeManager.getProjectRoot(),
245	   245	                        worktreeManager.getSymlinkDirs());
246	   246	            } catch (Exception e) {
247	   247	                return new ToolResult(false,
248	   248	                        "Error creating agent worktree: " + e.getMessage(), "WORKTREE_FAILED");
249	   249	            }
250	   250	        }
251	   251	
252	   252	        // Inject worktree notice into prompt
253	   253	        String effectivePrompt = prompt;
254	   254	        if (wtResult != null) {
255	   255	            String notice = AgentWorktree.buildNotice(System.getProperty("user.dir"),
256	   256	                    wtResult.worktreePath());
257	   257	            effectivePrompt = notice + "\n\n" + effectivePrompt;
258	   258	        }
259	   259	        String taskMessage = ForkBuilder.buildTaskMessage(effectivePrompt);
260	   260	        forkedConversationManager.addUserMessage(taskMessage);
261	   261	
262	   262	        // Create sub-agent
263	   263	        AgentLoop subAgent = createSubAgent(forkedConversationManager, forkSpec, forkFilter, modelOverride, name,
264	   264	                wtResult != null ? wtResult.worktreePath() : workingDirectory);
265	   265	
266	   266	        if (parentReplacementState != null) {
267	   267	            subAgent.setReplacementState(parentReplacementState.copy());
268	   268	        }
269	   269	
270	   270	        // Launch in background with worktree cleanup
271	   271	        return launchBackgroundTask(subAgent, forkSpec, description, name, wtResult);
272	   272	    }
