281	   281	            String slug = generateWorktreeSlug();
282	   282	            try {
283	   283	                wtResult = AgentWorktree.create(slug, worktreeManager.getProjectRoot(),
284	   284	                        worktreeManager.getSymlinkDirs());
285	   285	            } catch (Exception e) {
286	   286	                return new ToolResult(false,
287	   287	                        "Error creating agent worktree: " + e.getMessage(), "WORKTREE_FAILED");
288	   288	            }
289	   289	        }
290	   290	
291	   291	        String effectivePrompt = prompt;
292	   292	        if (wtResult != null) {
293	   293	            String notice = AgentWorktree.buildNotice(System.getProperty("user.dir"),
294	   294	                    wtResult.worktreePath());
295	   295	            effectivePrompt = notice + "\n\n" + effectivePrompt;
296	   296	        }
297	   297	
298	   298	        ConversationManager subConv = new ConversationManager();
299	   299	
300	   300	        // Inject system prompt if specified
301	   301	        if (spec.systemPromptOverride() != null && !spec.systemPromptOverride().isEmpty()) {
302	   302	            subConv.getMessagesMutable().add(
303	   303	                    new com.mewcode.conversation.Message("user",
304	   304	                            "<system-reminder>\n" + spec.systemPromptOverride() + "\n</system-reminder>"));
305	   305	        }
306	   306	
307	   307	        // Add task
308	   308	        subConv.addUserMessage(effectivePrompt);
309	   309	
310	   310	        // Build tool filter
311	   311	        Predicate<String> toolFilter = ToolFilter.buildFilter(spec, false, false);
312	   312	
313	   313	        // Create sub-agent
314	   314	        String workDir = wtResult != null ? wtResult.worktreePath() : workingDirectory;
315	   315	        AgentLoop subAgent = createSubAgent(subConv, spec, toolFilter, modelOverride, null, workDir);
316	   316	
317	   317	        // Run with auto-background timeout (and worktree cleanup on sync path)
318	   318	        return runWithTimeout(subAgent, spec, description, effectivePrompt, null, wtResult);
319	   319	    }
