399	   399	    // ── Background launch ───
400	   400	
401	   401	    private ToolResult launchBackgroundTask(AgentLoop subAgent, SubAgentSpec spec, String description, String name,
402	   402	                                            AgentWorktree.Result worktreeResult) {
403	   403	
404	   404	        String taskName = name != null ? name : description;
405	   405	        String taskId = taskManager.createTask(taskName);
406	   406	
407	   407	        Thread thread = Thread.startVirtualThread(() -> {
408	   408	            taskManager.setRunning(taskId, Thread.currentThread());
409	   409	            try {
410	   410	                String result = subAgent.runToCompletion();
411	   411	
412	   412	                // Worktree cleanup after background completion
413	   413	                if (worktreeResult != null) {
414	   414	                    result = appendWorktreeInfo(result, worktreeResult);
415	   415	                }
416	   416	
417	   417	                taskManager.setCompleted(taskId, result);
418	   418	            } catch (Exception e) {
419	   419	                taskManager.setFailed(taskId, "Sub-agent error: " + e.getMessage());
420	   420	                // Best-effort cleanup on failure
421	   421	                if (worktreeResult != null) {
422	   422	                    AgentWorktree.remove(worktreeResult.worktreePath(),
423	   423	                            worktreeResult.worktreeBranch(), worktreeResult.gitRoot());
424	   424	                }
425	   425	            }
426	   426	        });
427	   427	
428	   428	        taskManager.setRunning(taskId, thread);
429	   429	
430	   430	        return new ToolResult(true,
431	   431	                "{\"task_id\": \"" + taskId + "\", \"status\": \"async_launched\", "
432	   432	                        + "\"description\": \"" + escapeJson(description) + "\", "
433	   433	                        + "\"hint\": \"任务完成后会自动通知你，无需轮询 TaskGet/TaskList\"}");
434	   434	    }
