436	   436	    // ── Sync with timeout ─────────────────────────────────────────────────
437	   437	
438	   438	    private ToolResult runWithTimeout(AgentLoop subAgent, SubAgentSpec spec,
439	   439	                                       String description, String prompt, String name,
440	   440	                                       AgentWorktree.Result wtResult) {
441	   441	        String taskName = name != null ? name : ("sync-" + spec.name());
442	   442	        String taskId = taskManager.createTask(taskName);
443	   443	
444	   444	        Thread agentThread = Thread.startVirtualThread(() -> {
445	   445	            taskManager.setRunning(taskId, Thread.currentThread());
446	   446	            try {
447	   447	                String result = subAgent.runToCompletion();
448	   448	                // Worktree cleanup after sync completion
449	   449	                if (wtResult != null) {
450	   450	                    result = appendWorktreeInfo(result, wtResult);
451	   451	                }
452	   452	                taskManager.setCompleted(taskId, result);
453	   453	            } catch (Exception e) {
454	   454	                taskManager.setFailed(taskId, "Sub-agent error: " + e.getMessage());
455	   455	                // Best-effort cleanup on failure
456	   456	                if (wtResult != null) {
457	   457	                    AgentWorktree.remove(wtResult.worktreePath(),
458	   458	                            wtResult.worktreeBranch(), wtResult.gitRoot());
459	   459	                }
460	   460	            }
461	   461	        });
462	   462	        taskManager.setRunning(taskId, agentThread);
463	   463	
464	   464	        // Wait with timeout on the main thread
465	   465	        try {
466	   466	            long startTimeMillis = System.currentTimeMillis();
467	   467	            while (true) {
468	   468	                long diffTimeMillis = System.currentTimeMillis() - startTimeMillis;
469	   469	                if (diffTimeMillis >= AUTO_BACKGROUND_MS) {
470	   470	                    // Timed out — continues in background
471	   471	                    return new ToolResult(true,
472	   472	                            "{\"task_id\": \"" + taskId + "\", \"status\": \"timed_out_to_background\", "
473	   473	                                    + "\"description\": \"" + escapeJson(description) + "\", "
474	   474	                                    + "\"hint\": \"任务仍在后台运行，完成后会自动通知你\"}");
475	   475	                }
476	   476	
477	   477	                BackgroundTask task = taskManager.getTask(taskId);
478	   478	                if (task != null && task.isTerminal()) {
479	   479	                    if (task.getStatus() == BackgroundTask.Status.COMPLETED) {
480	   480	                        return new ToolResult(true, task.getResult() != null ? task.getResult() : "");
481	   481	                    } else {
482	   482	                        return new ToolResult(false, task.getError() != null ? task.getError() : "Sub-agent failed",
483	   483	                                "SUB_AGENT_FAILED");
484	   484	                    }
485	   485	                }
486	   486	
487	   487	                Thread.sleep(200); // poll interval
488	   488	            }
489	   489	        } catch (InterruptedException e) {
490	   490	            Thread.currentThread().interrupt();
491	   491	            return new ToolResult(false, "Sub-agent was interrupted", "INTERRUPTED");
492	   492	        }
493	   493	    }
