497	   497	    /**
498	   498	     * Generate a random worktree slug: "agent-a" + 7 hex digits.
499	   499	     */
500	   500	    private static String generateWorktreeSlug() {
501	   501	        byte[] rndBytes = new byte[4];
502	   502	        new SecureRandom().nextBytes(rndBytes);
503	   503	        return "agent-a" + HexFormat.of().formatHex(rndBytes).substring(0, 7);
504	   504	    }
