506	   506	    /**
507	   507	     * After sub-agent completion, check worktree for changes
508	   508	     */
509	   509	    private static String appendWorktreeInfo(String result, AgentWorktree.Result worktreeResult) {
510	   510	        String safeResult = result != null ? result : "";
511	   511	        if (WorktreeChanges.hasChanges(worktreeResult.worktreePath(), worktreeResult.headCommit())) {
512	   512	            return safeResult + "\n\nWorktree kept at %s (branch %s) — has uncommitted changes or new commits."
513	   513	                    .formatted(worktreeResult.worktreePath(), worktreeResult.worktreeBranch());
514	   514	        } else {
515	   515	            AgentWorktree.remove(worktreeResult.worktreePath(), worktreeResult.worktreeBranch(), worktreeResult.gitRoot());
516	   516	            return safeResult;
517	   517	        }
518	   518	    }
