376	   376	    /**
377	   377	     * Start a daemon thread that consumes AgentEvents from the queue and renders
378	   378	     * them via StreamingDisplay.
379	   379	     */
380	   380	    private static Thread startEventConsumer(BlockingQueue<AgentEvent> queue, StreamingDisplay display,
381	   381	                                              TerminalUI ui, PermissionChecker permissionChecker) {
382	   382	        Thread consumer = new Thread(() -> {
383	   383	            PrintWriter writer = ui.getWriter();
384	   384	            while (true) {
385	   385	                try {
386	   386	                    AgentEvent event = queue.take();
387	   387	
388	   388	                    switch (event.getType()) {
389	   389	                        case TEXT_DELTA -> {
390	   390	                            if (event.getText() != null && event.getChunkType() != null) {
391	   391	                                display.onChunk(event.getText(), event.getChunkType());
392	   392	                            }
393	   393	                        }
394	   394	                        case TOOL_CALL_START -> {
395	   395	                            writer.println("\n ⚙ 正在执行工具 " + event.getToolName() + "...");
396	   396	                            writer.flush();
397	   397	                        }
398	   398	                        case TOOL_CALL_RESULT -> {
399	   399	                            // Tool results are fed back to the model; no UI display needed
400	   400	                        }
401	   401	                        case TOKEN_USAGE -> {
402	   402	                            long create = event.getCacheCreationTokens();
403	   403	                            long read = event.getCacheReadTokens();
404	   404	                            if (create > 0 || read > 0) {
405	   405	                                writer.print("[cache: " + read + " tokens read, " + create + " created]");
406	   406	                                writer.flush();
407	   407	                            }
408	   408	                            // Update token counts for /status display
409	   409	                            ui.setTokenCounts(event.getInputTokens(), event.getOutputTokens());
410	   410	                        }
411	   411	                        case PROGRESS -> {
412	   412	                            // Progress messages are for internal tracking; skip UI noise
413	   413	                        }
414	   414	                        case COMPACT -> {
415	   415	                            if (event.getMessage() != null && !event.getMessage().isEmpty()) {
416	   416	                                writer.println(" ⏤ " + event.getMessage());
417	   417	                                writer.flush();
418	   418	                            }
419	   419	                        }
420	   420	                        case LOOP_STARTED -> {
421	   421	                            // Agent loop begins — nothing to display
422	   422	                        }
423	   423	                        case LOOP_FINISHED -> {
424	   424	                            display.onComplete();
425	   425	                            writer.println("✓ 完成");
426	   426	                            writer.flush();
427	   427	                        }
428	   428	                        case ERROR -> {
429	   429	                            display.onComplete();
430	   430	                            writer.println("✗ " + (event.getMessage() != null ? event.getMessage() : "未知错误"));
431	   431	                            writer.flush();
432	   432	                        }
433	   433	                        case CANCELLED -> {
434	   434	                            display.onComplete();
435	   435	                            writer.println("⊘ " + (event.getMessage() != null ? event.getMessage() : "已取消"));
436	   436	                            writer.flush();
437	   437	                        }
438	   438	                        case UNKNOWN_TOOL -> {
439	   439	                            display.onComplete();
440	   440	                            writer.println("✗ " + (event.getMessage() != null ? event.getMessage() : "未知工具"));
441	   441	                            writer.flush();
442	   442	                        }
443	   443	                        case PERMISSION_REQUIRED -> {
444	   444	                            // Render the permission confirmation prompt
445	   445	                            ToolCall tc = event.getPermissionToolCall();
446	   446	                            String toolName = event.getToolName() != null ? event.getToolName() : "?";
447	   447	                            String description = event.getMessage() != null ? event.getMessage() : "需要用户确认";
448	   448	
449	   449	                            writer.println();
450	   450	                            writer.println("════════════════════权限确认 ════════════════════");
451	   451	                            writer.println(" 工具: " + toolName);
452	   452	                            writer.println(" 操作: " + description);
453	   453	                            writer.println("════════════════════════════════════════════════");
454	   454	                            writer.println(" [Y] 本次放行  [A] 总是放行(本会话)  [N] 拒绝");
455	   455	                            writer.println("════════════════════════════════════════════════");
456	   456	                            writer.flush();
457	   457	                        }
458	   458	                        case PERMISSION_RESPONSE -> {
459	   459	                            // Handled inside AgentLoop via permissionResponseQueue;
460	   460	                            // no rendering needed here.
461	   461	                        }
462	   462	                        case MEMORY_TICK -> {
463	   463	                            // Memory extraction may be triggered asynchronously;
464	   464	                            // no rendering needed here.
465	   465	                        }
466	   466	                    }
467	   467	                } catch (InterruptedException e) {
468	   468	                    break; // consumer thread shutting down
469	   469	                } catch (Exception e) {
470	   470	                    writer.println("[事件消费异常] " + e.getMessage());
471	   471	                    writer.flush();
472	   472	                }
473	   473	            }
474	   474	        }, "event-consumer");
475	   475	        consumer.setDaemon(true);
476	   476	        consumer.start();
477	   477	        return consumer;
478	   478	    }
