 57	        try {
 58	            // 1. Load configuration
 59	            // Strategy: 
 60	            //   - If command line arg provided, use that path
 61	            //   - Otherwise, try ./mewcode.yaml first (user config)
 62	            //   - If not found, load mewcode.yaml from classpath (built-in default)
 63	            String configPath;
 64	            AppConfig config;
 65	            
 66	            if (args.length > 0) {
 67	                // User specified config path
 68	                configPath = args[0];
 69	                config = ConfigLoader.load(configPath);
 70	            } else {
 71	                File userConfig = new File("./mewcode.yaml");
 72	                if (userConfig.exists()) {
 73	                    // Use user's config file
 74	                    configPath = "./mewcode.yaml";
 75	                    config = ConfigLoader.load(configPath);
 76	                } else {
 77	                    // Use built-in default from classpath
 78	                    configPath = "classpath:mewcode.yaml"; // for display purposes
 79	                    config = ConfigLoader.loadFromClasspath();
 80	                }
 81	            }
 82	
 83	            // 1b. Resolve project root and working directory
 84	            Path projectRoot;
 85	            if (configPath.startsWith("classpath:")) {
 86	                // When loading from classpath, use current directory as project root
 87	                projectRoot = Paths.get(".").toAbsolutePath().normalize();
 88	            } else {
 89	                Path configFile = Paths.get(configPath).toAbsolutePath();
 90	                projectRoot = configFile.getParent();
 91	                if (projectRoot == null) {
 92	                    projectRoot = Paths.get(".").toAbsolutePath();
 93	                }
 94	            }
 95	            projectRoot = projectRoot.toRealPath();
 96	            String workingDirectory = projectRoot.toString();
 97	
 98	            // 1c. Load project instructions
 99	            String instructionsContent = InstructionsLoader.load(workingDirectory);
100	
101	            // 1d. Initialize memory manager
102	            MemoryManager memoryManager = new MemoryManager(workingDirectory);
103	            MemoryExtractor memoryExtractor = new MemoryExtractor();
104	
105	            // 1e. Clean up expired sessions
106	            int maxSessionAgeDays = config.getMaxSessionAgeDays() > 0 ? config.getMaxSessionAgeDays() : 5;
107	            SessionCleanup.cleanIfNeeded(workingDirectory, maxSessionAgeDays);
108	
109	            // 1f. Generate session ID for this run.
110	            // Mutable holder: /resume replaces the value so subsequent messages
111	            // append to the resumed session's JSONL file, not a new one.
112	            String[] sessionIdHolder = { SessionManager.newId() };
113	
114	            // 1g. Load sub-agent definitions
115	            AgentCatalog agentCatalog = AgentLoader.loadAll(projectRoot);
116	
117	            // 2. Build tool registry (built-in tools)
