122	
123	            // 2b. Create worktree manager (if enabled)
124	            AppConfig.WorktreeConfig worktreeConfig = config.getWorktree();
125	            WorktreeManager worktreeManager = null;
126	            ScheduledExecutorService cleanupExecutor = null;
127	            if (worktreeConfig.isEnabled()) {
128	                worktreeManager = new WorktreeManager(workingDirectory,
129	                        worktreeConfig.getSymlinkDirs(), worktreeConfig.getStaleCutoffHours());
130	            }
131	
132	            // 3. Create provider
133	            LLMProvider provider = ProviderFactory.create(config, toolRegistry);
134	
135	            // 4. Terminal UI (create early so MCP can use its writer for UTF-8 output)
136	            TerminalUI ui = new TerminalUI();
137	            ui.setWorkingDirectory(workingDirectory);
138	            ui.setMemoryManager(memoryManager);
139	            ui.setModel(config.getModel());
140	            // Wire resume callback: update sessionId so subsequent saves
141	            // append to the resumed session's JSONL file, not a new one.
142	            ui.setResumeCallback(resumedId -> {
143	                sessionIdHolder[0] = resumedId;
144	                ui.setCurrentSessionId(resumedId);
145	            });
146	
147	            // 2b. Connect MCP servers and register their tools (AFTER UI is created)
