288	            // 11. Start interactive input loop
289	            ui.start(input -> {
290	                // If an agent is waiting for permission, dispatch input there
291	                if (currentAgent[0] != null && currentAgent[0].isWaitingForPermission()) {
292	                    currentAgent[0].respondToPermission(input.trim());
293	                    return;
294	                }
295	
296	                // Cancel any in-flight agent
297	                if (currentAgent[0] != null) {
298	                    currentAgent[0].cancel();
299	                }
300	
301	                // Add user message to conversation
302	                conversation.addUserMessage(input);
303	
304	                // Save user message to session JSONL
305	                SessionManager.saveMessage(workingDirectory, sessionIdHolder[0], "user", input);
306	
307	                // Create agent loop
308	                AgentLoop agent = new AgentLoop(
309	                        provider,
310	                        toolRegistry,
311	                        conversation,
312	                        eventQueue,
313	                        config.getMaxIterations(),
314	                        config.getStreamTimeoutSeconds(),
315	                        permissionChecker
316	                );
317	                agent.setPlanMode(ui.isPlanMode());
318	                agent.setWorkingDirectory(workingDirectory);
319	                agent.setSessionId(sessionIdHolder[0]);
320	                // Wire memory extraction
321	                agent.setMemoryExtractor(memoryExtractor);
322	                agent.setMemoryManager(memoryManager);
323	                agent.setProviderForMemory(provider);
324	                agent.setHookEngine(hookEngine);
325	
326	                // Wire AgentTool: update parent conversation each turn (for Fork support)
327	                agentTool.setParentConversation(conversation);
328	                agentTool.setParentReplacementState(agent.getReplacementState());
329	
330	                // Wire TaskManager: drain completed notifications before each turn
331	                agent.setNotificationFn(() -> {
332	                    var notes = new java.util.ArrayList<String>();
333	                    for (var n : taskManager.drainNotifications()) {
334	                        notes.add(n.format());
335	                    }
336	                    return notes;
337	                });
338	                currentAgent[0] = agent;
339	
340	                // Wire agent loop to TerminalUI for /compact command
341	                ui.setAgentLoop(agent);
342	
343	                // Run agent on its own thread
344	                Thread agentThread = new Thread(agent, "agent-loop");
345	                agentThread.start();
346	            }, () -> {
347	                conversation.clear();
348	                // Clear active skills when conversation is cleared
349	                if (currentAgent[0] != null) {
350	                    currentAgent[0].clearActiveSkills();
351	                }
352	            });
353	
354	            // Cleanup
355	            if (currentAgent[0] != null) {
356	                currentAgent[0].cancel();
357	            }
358	            eventConsumer.interrupt();
359	            memoryExtractor.shutdown();
360	            if (cleanupExecutor != null) {
361	                cleanupExecutor.shutdownNow();
362	            }
363	
364	            // ---- hook: shutdown ----
365	            hookEngine.runHooks(EventName.SHUTDOWN, HookContext.of(EventName.SHUTDOWN));
366	
367	            // Shutdown MCP connections
368	            shutdownMcp(mcpManager);
369	
370	        } catch (Exception e) {
371	            System.err.println("启动失败: " + e.getMessage());
372	            System.exit(1);
373	        }
