480	    private static ToolRegistry buildToolRegistry(AppConfig config) {
481	        String wd = config.getTool().getWorkingDirectory();
482	        int timeout = config.getTool().getTimeoutSeconds();
483	
484	        ToolRegistry registry = new ToolRegistry();
485	        registry.register(new ToolSearchTool(registry));
486	        registry.registerAll(
487	                new ReadFileTool(wd),
488	                new WriteFileTool(wd),
489	                new EditFileTool(wd),
490	                new GlobTool(wd),
491	                new GrepTool(wd),
492	                new ExecuteCommandTool(wd, timeout)
493	        );
494	        return registry;
495	    }
